import { Link, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";

export default function Navbar() {
  const navigate = useNavigate();
  const [token, setToken] = useState(localStorage.getItem("token"));
  const [role, setRole] = useState(localStorage.getItem("role")); // admin / staff / user

  // Keep navbar synced (login/logout)
  useEffect(() => {
    const sync = () => {
      setToken(localStorage.getItem("token"));
      setRole(localStorage.getItem("role"));
    };

    window.addEventListener("storage", sync);

    // Also sync when route changes / component re-renders
    sync();

    return () => window.removeEventListener("storage", sync);
  }, []);

  const logout = () => {
    localStorage.clear();
    setToken(null);
    setRole(null);
    navigate("/login");
  };

  const isLogged = !!token;
  const isAdmin = role === "admin";
  const isStaff = role === "staff";
  const isCustomer = role === "user";

  return (
    <nav style={styles.nav}>
      {/* Left */}
      <div style={styles.left}>
        <Link to="/vehicles" style={styles.link}>Home</Link>

        {/* ADMIN */}
        {isLogged && isAdmin && (
          <>
            <Link to="/vehicles" style={styles.link}>Vehicles</Link>
            <Link to="/leads" style={styles.link}>Leads</Link>
            <Link to="/appointments" style={styles.link}>Appointments</Link>
            <Link to="/users" style={styles.link}>Users</Link>
          </>
        )}

        {/* STAFF */}
        {isLogged && isStaff && (
          <>
            <Link to="/vehicles" style={styles.link}>Vehicles</Link>
            <Link to="/leads" style={styles.link}>Leads</Link>
            <Link to="/appointments" style={styles.link}>Appointments</Link>
          </>
        )}

        {/* CUSTOMER */}
        {isLogged && isCustomer && (
          <>
            <Link to="/vehicles" style={styles.link}>Browse Vehicles</Link>
            <Link to="/book-appointment" style={styles.link}>Book Appointment</Link>
            <Link to="/my-appointments" style={styles.link}>My Appointments</Link>
          </>
        )}
      </div>

      {/* Right */}
      <div style={styles.right}>
        {isLogged ? (
          <>
            <span style={styles.roleTag}>
              {role?.toUpperCase()}
            </span>
            <button onClick={logout} style={styles.btn}>
              Logout
            </button>
          </>
        ) : (
          <>
            <Link to="/login" style={styles.link}>Login</Link>
            <Link to="/register" style={styles.link}>Register</Link>
          </>
        )}
      </div>
    </nav>
  );
}

const styles = {
  nav: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "12px 24px",
    background: "#111",
    color: "#fff",
  },
  left: { display: "flex", alignItems: "center" },
  right: { display: "flex", alignItems: "center" },
  link: {
    color: "#fff",
    textDecoration: "none",
    marginRight: 16,
    fontWeight: 500,
  },
  roleTag: {
    marginRight: 12,
    padding: "4px 10px",
    border: "1px solid #444",
    borderRadius: 20,
    fontSize: 12,
    opacity: 0.9,
  },
  btn: {
    padding: "6px 12px",
    borderRadius: 6,
    border: "none",
    background: "#ff4d4d",
    color: "#fff",
    cursor: "pointer",
  },
};
